int maximum_mex(int[] nums, int value) {
    HashSet<Integer> st = new HashSet<>();

    for (int num : nums)
        st.add(num);

    for (int i = 0; i <= 100000; i++) {
        if (!st.contains(i))
            st.add(i + value);
    }

    int mex = 0;
    while (st.contains(mex))
        mex++;

    return mex;
}
```

